import redis

# Redis cluster configuration
redis_nodes = [
    {"host": "redis1.example.com", "port": 6379},
    {"host": "redis2.example.com", "port": 6379},
    # ... additional nodes
]

# Create a Redis cluster client
redis_cluster = redis.RedisCluster(
    startup_nodes=redis_nodes, decode_responses=True
)

# Set sensitive user data with TTL
user_session_token = "abc123"
user_api_key = "def456"

# Store session token in Redis with a TTL of 3600 seconds
redis_cluster.setex("user_session_token", user_session_token, 3600)

# Store API key in Redis with a TTL of 86400 seconds
redis_cluster.setex("user_api_key", user_api_key, 86400)